// Helper to build Gemini request payload
function buildGeminiPayload(systemPrompt, userPrompt) {
  return {
    contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
    systemInstruction: { parts: [{ text: systemPrompt }] },
    generationConfig: { temperature: 0.4, maxOutputTokens: 8192, responseMimeType: 'application/json' }
  };
}

const reqs = $input.first().json[0];
const prdSummary = reqs.prd_content.substring(0, 3000); // Truncate for token efficiency

const pmPayload = buildGeminiPayload(
  'You are a senior Product Manager. Produce a detailed sprint plan and task breakdown as JSON.',
  `PRD:\n${prdSummary}\n\nCreate: final task breakdown, sprint plan, acceptance criteria per task.`
);

return [{ json: {
  requirements: reqs,
  project_id: $('Execute Workflow Trigger').first().json.project_id,
  requirements_id: $('Execute Workflow Trigger').first().json.requirements_id,
  github_repo_name: $('Execute Workflow Trigger').first().json.github_repo_name,
  github_repo_url: $('Execute Workflow Trigger').first().json.github_repo_url,
  pm_payload: pmPayload
} }];

const pmResponse = $input.first().json;
const pmOutput = pmResponse.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const projectId = $('Prepare PM Request').first().json.project_id;
const requirementsId = $('Prepare PM Request').first().json.requirements_id;
const reqs = $('Prepare PM Request').first().json.requirements;

// Build architect payload using PM output
const architectPayload = {
  contents: [{ role: 'user', parts: [{ text: `PRD:\n${reqs.prd_content.substring(0, 2000)}\n\nPM Sprint Plan:\n${pmOutput.substring(0, 2000)}\n\nDesign the complete technical architecture.` }] }],
  systemInstruction: { parts: [{ text: 'You are a senior Software Architect. Produce a complete architecture specification as JSON.' }] },
  generationConfig: { temperature: 0.3, maxOutputTokens: 8192, responseMimeType: 'application/json' }
};

return [{ json: {
  ...($('Prepare PM Request').first().json),
  pm_output: pmOutput,
  architect_payload: architectPayload
} }];

const archResponse = $input.first().json;
const archOutput = archResponse.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const context = $('Save PM Output').first().json;

const baseContext = `PRD Summary:\n${context.requirements.prd_content.substring(0, 1500)}\n\nArchitecture:\n${archOutput.substring(0, 2000)}`;

function buildAgentPayload(role, task) {
  return {
    contents: [{ role: 'user', parts: [{ text: `${baseContext}\n\n${task}` }] }],
    systemInstruction: { parts: [{ text: `You are a senior ${role}. Produce complete specifications as JSON.` }] },
    generationConfig: { temperature: 0.3, maxOutputTokens: 8192, responseMimeType: 'application/json' }
  };
}

return [{ json: {
  ...context,
  architect_output: archOutput,
  ux_payload: buildAgentPayload('UX/UI Designer', 'Design all pages, components, user flows, and the design system.'),
  backend_payload: buildAgentPayload('Backend Engineer', 'Design all Supabase Edge Functions, auth flows, and database operations.'),
  frontend_payload: buildAgentPayload('Frontend Engineer', 'Specify all React components, pages, hooks, and configuration files.'),
  db_payload: buildAgentPayload('Database Engineer', 'Design all SQL migrations, RLS policies, indexes, and database functions.')
} }];

const inputs = $input.all();
// Collect all agent outputs
const uxOutput = inputs[0]?.json?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const backendOutput = inputs[1]?.json?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const frontendOutput = inputs[2]?.json?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const dbOutput = inputs[3]?.json?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

const context = $('Prepare Parallel Agent Requests').first().json;

const combinedContext = `Architecture:\n${context.architect_output.substring(0, 1500)}\nBackend:\n${backendOutput.substring(0, 1000)}\nFrontend:\n${frontendOutput.substring(0, 1000)}`;

function buildPayload(role, task) {
  return {
    contents: [{ role: 'user', parts: [{ text: `${combinedContext}\n\n${task}` }] }],
    systemInstruction: { parts: [{ text: `You are a senior ${role}. Produce complete specifications as JSON.` }] },
    generationConfig: { temperature: 0.3, maxOutputTokens: 8192, responseMimeType: 'application/json' }
  };
}

return [{ json: {
  ...context,
  ux_output: uxOutput,
  backend_output: backendOutput,
  frontend_output: frontendOutput,
  db_output: dbOutput,
  qa_payload: buildPayload('QA Engineer', 'Create a complete Playwright test suite covering navigation, auth, CRUD, API, and performance.'),
  devops_payload: buildPayload('DevOps Engineer', 'Create all deployment configuration for Vercel and GitHub Actions CI.'),
  security_payload: buildPayload('Security Auditor', 'Audit the architecture for OWASP Top 10 vulnerabilities and produce a security hardening plan.')
} }];

const qaText = $('Agent: QA Engineer').first().json?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const devopsText = $('Agent: DevOps Engineer').first().json?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const securityText = $('Agent: Security Auditor').first().json?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

const context = $('Prepare Sequential Agent Requests').first().json;
const projectId = context.project_id;
const requirementsId = context.requirements_id;

// Build task records for each agent
const agentOutputs = [
  { role: 'product_manager', output: context.pm_output },
  { role: 'architect', output: context.architect_output },
  { role: 'ux_ui_designer', output: context.ux_output },
  { role: 'backend_engineer', output: context.backend_output },
  { role: 'frontend_engineer', output: context.frontend_output },
  { role: 'database_engineer', output: context.db_output },
  { role: 'qa_engineer', output: qaText },
  { role: 'devops_engineer', output: devopsText },
  { role: 'security_auditor', output: securityText }
];

return agentOutputs.map(a => ({ json: {
  project_id: projectId,
  requirement_id: requirementsId,
  assigned_agent: a.role,
  title: `${a.role.replace(/_/g, ' ')} analysis`,
  description: `Automated ${a.role} specification for project`,
  context: { agent_output_preview: a.output.substring(0, 500) },
  raw_output: a.output,
  all_outputs: agentOutputs.reduce((acc, o) => { acc[o.role] = o.output; return acc; }, {}),
  github_repo_name: context.github_repo_name,
  github_repo_url: context.github_repo_url
} }));
